xml.src:

import {InuMainHeader} from 'inugami-ng/components/inu-main-header';

@Component({
  selector: 'app-root',
             imports: [
               RouterOutlet,
               InuMainHeader
             ],
  templateUrl: './app.html',
  styleUrl: './app.scss'
})
export class App {
  links = signal<InuSiteLink[]>([
    {
      title   : 'Inugami Framework',
      path    : 'https://inugami.io/inugami/framework',
      external: true
    }
    // ...
  ]);
}


export interface InuSiteLink{
  title:string;
  path:string;
  icon?:string;
  styleClass?:string;
  external?:boolean;
  target?:'_blank'|'_self'|'_parent',
  children?: InuSiteLinkChildren[];
  gaEvent?:string;
  gaCategory?:string;
}

export interface  InuSiteLinkChildren{
  links?: InuSiteLink[];
  title?:string;
}
